Step-by-step setup:
1. `mkdir backend && cd backend && npm init -y`
2. `npm install express cors dotenv @prisma/client` and `npm install -D prisma nodemon`
3. `npx prisma init`
4. Update connection string in `.env` to: `DATABASE_URL="postgresql://postgres:password@localhost:5432/capstone"`
5. Define model in `schema.prisma`:
```prisma
model User {
  id String @id @default(uuid())
  email String @unique
  password String
  createdAt DateTime @default(now())
}
```
6. Run migrations: `npx prisma migrate dev --name init`
7. Write Express `server.js` health route:
```javascript
app.get('/health', async (req, res) => {
  await prisma.$queryRaw`SELECT 1`;
  res.json({ status: 'OK' });
});
```
8. Run nodemon server.

Step-by-step JWT middleware configuration:
1. `npm install jsonwebtoken bcryptjs`. Add `JWT_SECRET="mysecretkey"` to `.env`.
2. Create middleware file `middleware/auth.js`:
```javascript
import jwt from 'jsonwebtoken';
export function protect(req, res, next) {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Token missing' });
  }
  const token = authHeader.split(' ')[1];
  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;
    next();
  } catch (error) {
    return res.status(401).json({ error: 'Token failed' });
  }
}
```
3. Protect route:
```javascript
app.get('/api/secure-data', protect, (req, res) => res.json({ user: req.user }));
```

Chunking and vector loaders setup:
1. `npm install @pinecone-database/pinecone openai`
2. Create file `ingest_docs.js`:
```javascript
import { Pinecone } from '@pinecone-database/pinecone';
import { OpenAI } from 'openai';
const openai = new OpenAI();
const pc = new Pinecone({ apiKey: process.env.PINECONE_API_KEY });
const index = pc.Index('capstone-rag');

async function ingest() {
  const chunk = "React is a single-page app library.";
  const response = await openai.embeddings.create({
    model: 'text-embedding-3-small',
    input: chunk
  });
  const vector = response.data[0].embedding;
  await index.namespace('course-material').upsert([{
    id: 'react-chunk-1',
    values: vector,
    metadata: { text: chunk }
  }]);
}
ingest();
```

Build a Server-Sent Events controller and consumer client:
1. Server Stream handler:
```javascript
app.get('/api/ai/stream', async (req, res) => {
  res.setHeader('Content-Type', 'text/event-stream');
  res.setHeader('Cache-Control', 'no-cache');
  res.setHeader('Connection', 'keep-alive');
  const stream = await openai.chat.completions.create({
    model: 'gpt-4o-mini',
    messages: [{ role: 'user', content: req.query.prompt }],
    stream: true,
  });
  for await (const chunk of stream) {
    const content = chunk.choices[0]?.delta?.content || '';
    res.write(`data: ${JSON.stringify({ content })}\n\n`);
  }
  res.end();
});
```
2. React front-end stream reader:
```javascript
const res = await fetch(`/api/ai/stream?prompt=${encodeURIComponent(input)}`);
const reader = res.body.getReader();
const decoder = new TextDecoder();
while (true) {
  const { done, value } = await reader.read();
  if (done) break;
  const text = decoder.decode(value);
  const lines = text.split('\n\n');
  for (const line of lines) {
    if (line.startsWith('data: ')) {
      const data = JSON.parse(line.slice(6));
      setMessages(prev => updateMessage(prev, data.content));
    }
  }
}
```
